```plantuml
@startuml
class MediumDungeon {
  + newBokoblin() : Bokoblin
  + newMoblin() : Moblin
}

class EasyDungeon {
  + newBokoblin() : Bokoblin
  + newMoblin() : Moblin
}

class Encounter {
  - enemies : [Monster]
  - dungeon : Dungeon
  + announceEnemies()
  + moveEnemies()
}

class BlueBokoblin {
  + announce()
  + move()
  + bludgeon()
  + defend()
}

class BlueMoblin {
  + announce()
  + move()
  + stab()
  + kick()
}

class NormalBokoblin {
  + announce()
  + move()
  + bludgeon()
  + defend()
}

interface Dungeon {
  + newBokoblin() : Bokoblin
  + newMoblin() : Moblin
}

class NormalMoblin {
  + announce()
  + move()
  + stab()
  + kick()
}

interface Bokoblin {
  + bludgeon()
  + defend()
}

interface Moblin {
  + stab()
  + kick()
}

interface Monster {
  + announce()
  + move()
}

MediumDungeon ..> BlueBokoblin
MediumDungeon ..> BlueMoblin
MediumDungeon ..|> Dungeon

EasyDungeon ..> NormalBokoblin
EasyDungeon ..> NormalMoblin
EasyDungeon ..|> Dungeon

Encounter o--> Dungeon
Encounter o--> Monster

BlueBokoblin ..|> Bokoblin
BlueMoblin ..|> Moblin
NormalBokoblin ..|> Bokoblin
NormalMoblin ..|> Moblin

Dungeon ..> Bokoblin
Dungeon ..> Moblin

Bokoblin ..|> Monster
Moblin ..|> Monster

@enduml
```
